sql:
SELECT ordinary_shares, beginning_balance
FROM shareholders_equity
WHERE equity_id = 1;

SELECT se.*
FROM shareholders_equity se
WHERE se.total > (
    se.ordinary_shares + se.additional_paid_in_capital + (
        SELECT COALESCE(SUM(fc.value), 0)
        FROM financial_components fc
        WHERE fc.component_type = 'adjustment to ordinary shares'
        AND fc.equity_id = se.equity_id
    )
);

SELECT period_id, start_date
   FROM financial_periods
   ORDER BY start_date DESC;

SELECT fp.period_id, fp.start_date, fp.end_date, fp.period_type, fp.fiscal_year, fp.is_closed, fp.created_at, fp.updated_at
FROM financial_periods fp
INNER JOIN shareholders_equity se ON fp.period_id = se.period_id;

SELECT users.user_name
FROM users
INNER JOIN financial_periods ON users.created_at = financial_periods.created_at;

SELECT fc.component_type, se.ordinary_shares
FROM shareholders_equity se
JOIN financial_components fc ON se.equity_id = fc.equity_id;

SELECT component_id, equity_id, value
FROM financial_components
WHERE STRFTIME('%m', created_at) = '02' AND CAST(REPLACE(value, ',', '') AS REAL) < -50000;

SELECT SUM(ordinary_shares) AS total_ordinary_shares
FROM shareholders_equity
WHERE period_id = 1;

SELECT total
FROM shareholders_equity
WHERE ending_balance = (SELECT MAX(ending_balance) FROM shareholders_equity);

SELECT fc.component_id, fc.component_type
FROM financial_components fc
WHERE fc.component_type = 'net loss';

